import { describe, expect, it } from 'vitest';

import {
  allStandardModelBosons,
  bosonPhaseCount,
  bosonSkyrmsEquilibrium,
  classifyBosonEquilibrium,
  isHiggsEquilibrium,
  type StandardModelBoson,
} from '../src/boson-skyrms';
import {
  TOWER_CEILINGS,
  vacuumBuleyProjection,
  type BuleyProjection,
} from '../src/spectral-noise-monitor';

describe('boson catalog', () => {
  it('there are exactly 13 Standard Model bosons', () => {
    expect(allStandardModelBosons.length).toBe(13);
  });

  it('catalog is 1 photon + 2 W + 1 Z + 8 gluons + 1 Higgs', () => {
    const counts = {
      photon: 0,
      wPlus: 0,
      wMinus: 0,
      zZero: 0,
      gluon: 0,
      higgs: 0,
    };
    for (const b of allStandardModelBosons) {
      counts[b.kind]++;
    }
    expect(counts).toEqual({
      photon: 1,
      wPlus: 1,
      wMinus: 1,
      zZero: 1,
      gluon: 8,
      higgs: 1,
    });
  });
});

describe('phase counts', () => {
  it('electroweak bosons share the Triton phase (3)', () => {
    const electroweak: StandardModelBoson[] = [
      { kind: 'photon' },
      { kind: 'wPlus' },
      { kind: 'wMinus' },
      { kind: 'zZero' },
    ];
    for (const b of electroweak) {
      expect(bosonPhaseCount(b)).toBe(TOWER_CEILINGS.triton);
      expect(bosonPhaseCount(b)).toBe(3);
    }
  });

  it('all 8 gluons share the Octagon phase (8)', () => {
    for (let i = 0; i < 8; i++) {
      expect(bosonPhaseCount({ kind: 'gluon', index: i })).toBe(8);
    }
  });

  it('Higgs sits at the vacuum (phase 0)', () => {
    expect(bosonPhaseCount({ kind: 'higgs' })).toBe(0);
  });
});

describe('Skyrms equilibrium predicates', () => {
  it('photon equilibrium at score 3', () => {
    const b: BuleyProjection = { waste: 3, opportunity: 0, diversity: 0, score: 3 };
    expect(bosonSkyrmsEquilibrium(b, { kind: 'photon' })).toBe(true);
  });

  it('Z boson equilibrium at three-face balance (1, 1, 1)', () => {
    const b: BuleyProjection = { waste: 1, opportunity: 1, diversity: 1, score: 3 };
    expect(bosonSkyrmsEquilibrium(b, { kind: 'zZero' })).toBe(true);
  });

  it('gluon equilibrium at score 8 — same witness for all 8 gluons', () => {
    const b: BuleyProjection = { waste: 4, opportunity: 2, diversity: 2, score: 8 };
    for (let i = 0; i < 8; i++) {
      expect(bosonSkyrmsEquilibrium(b, { kind: 'gluon', index: i })).toBe(true);
    }
  });

  it('Higgs equilibrium iff the carrier is the vacuum', () => {
    expect(bosonSkyrmsEquilibrium(vacuumBuleyProjection, { kind: 'higgs' })).toBe(true);
    const nonVacuum: BuleyProjection = { waste: 1, opportunity: 0, diversity: 0, score: 1 };
    expect(bosonSkyrmsEquilibrium(nonVacuum, { kind: 'higgs' })).toBe(false);
  });

  it('isHiggsEquilibrium is the score-zero shortcut', () => {
    expect(isHiggsEquilibrium(vacuumBuleyProjection)).toBe(true);
    const b: BuleyProjection = { waste: 1, opportunity: 0, diversity: 0, score: 1 };
    expect(isHiggsEquilibrium(b)).toBe(false);
  });
});

describe('classification', () => {
  it('vacuum classifies as exactly the Higgs', () => {
    const result = classifyBosonEquilibrium(vacuumBuleyProjection);
    expect(result.length).toBe(1);
    expect(result[0]?.kind).toBe('higgs');
  });

  it('a score-3 carrier classifies as the four electroweak bosons', () => {
    const b: BuleyProjection = { waste: 1, opportunity: 1, diversity: 1, score: 3 };
    const result = classifyBosonEquilibrium(b);
    expect(result.length).toBe(4);
    const kinds = result.map((r) => r.kind).sort();
    expect(kinds).toEqual(['photon', 'wMinus', 'wPlus', 'zZero']);
  });

  it('a score-8 carrier classifies as all 8 gluons', () => {
    const b: BuleyProjection = { waste: 4, opportunity: 2, diversity: 2, score: 8 };
    const result = classifyBosonEquilibrium(b);
    expect(result.length).toBe(8);
    const indices = result
      .filter((r) => r.kind === 'gluon')
      .map((r) => (r.kind === 'gluon' ? r.index : -1))
      .sort((a, b) => a - b);
    expect(indices).toEqual([0, 1, 2, 3, 4, 5, 6, 7]);
  });

  it('a score-5 carrier matches no boson (between phase walls)', () => {
    const b: BuleyProjection = { waste: 5, opportunity: 0, diversity: 0, score: 5 };
    expect(classifyBosonEquilibrium(b)).toEqual([]);
  });

  it('a score-2 carrier (between vacuum and Triton) matches no boson', () => {
    const b: BuleyProjection = { waste: 2, opportunity: 0, diversity: 0, score: 2 };
    expect(classifyBosonEquilibrium(b)).toEqual([]);
  });
});
